hooks.command:
node -e "
const fs = require('fs');
const path = require('path');

const contractPath = path.join(process.cwd(), 'docs', 'architecture', 'API-CONTRACTS.yaml');

if (!fs.existsSync(contractPath)) {
  console.error('HOOK BLOCKED: docs/architecture/API-CONTRACTS.yaml does not exist.');
  console.error('API contracts must be defined by solution-architect before backend or frontend implementation begins.');
  console.error('Action: Return to solution-architect to produce API-CONTRACTS.yaml.');
  process.exit(2);
}

const content = fs.readFileSync(contractPath, 'utf8');

if (!content.includes('paths:')) {
  console.error('HOOK BLOCKED: API-CONTRACTS.yaml has no paths defined.');
  console.error('At least one API endpoint must be documented before implementation.');
  console.error('Action: Return to solution-architect to define API paths.');
  process.exit(2);
}

const pathMatches = content.match(/^  \//gm);
if (!pathMatches || pathMatches.length === 0) {
  console.error('HOOK BLOCKED: API-CONTRACTS.yaml paths section is empty.');
  console.error('Define at least one endpoint path before writing implementation code.');
  process.exit(2);
}

process.exit(0);
"
